import type { Transaction } from '@codemirror/state';
import type { ViewUpdate, EditorView } from '@codemirror/view';
import type { MutableRefObject } from 'react';

import {
  ANNOTATION_DOC_CHANGED_CONTROLLED,
  pastingEffect,
  stringAnnotation,
  type PastingInfo,
} from './editor-config.js';

/**
 * Update handler to manage pasting transactions.
 * @internal
 */
export function handlePastingTransaction(
  update: ViewUpdate,
  pastingInfoRef: MutableRefObject<PastingInfo>,
  editorView: EditorView,
  editorViewRef: MutableRefObject<EditorView | null>,
) {
  const isPastingStart = update.transactions.some((transaction) =>
    transaction.isUserEvent('input.paste'),
  );

  const isControlledUpdate = update.transactions.some((transaction) => {
    const annotation = transaction.annotation(stringAnnotation);
    if (annotation === ANNOTATION_DOC_CHANGED_CONTROLLED) {
      return true;
    }
    return false;
  });

  if (isPastingStart) {
    pastingInfoRef.current.pastingInProgress = true;
  }

  if (pastingInfoRef.current.pastingInProgress !== true) {
    return;
  }

  const isPastingEnd = update.transactions.some((transaction) => {
    return (
      transaction.isUserEvent('input.type') ||
      transaction.isUserEvent('delete') ||
      transaction.isUserEvent('select')
    );
  });

  if (
    isPastingEnd ||
    update.focusChanged ||
    pastingInfoRef.current.cancelPastingMode
  ) {
    pastingInfoRef.current = { pastingInProgress: false };
    editorView.dispatch({
      effects: [
        pastingEffect.of({
          pastingInProgress: false,
        }),
      ],
      // In order to re-run the decorations and re-generate errors and diagnostics,
      // we have to dispatch a new document.
      changes: {
        from: 0,
        to: editorViewRef.current?.state.doc.length,
        insert: editorViewRef.current?.state.doc,
      },
      selection: update.state.selection,
    });

    if (pastingInfoRef.current.cancelPastingMode) {
      pastingInfoRef.current.cancelPastingMode = false;
    }
  }

  if (
    (update.docChanged && isPastingStart) ||
    (isControlledUpdate && pastingInfoRef.current.pastingInProgress === true)
  ) {
    const changedRange = isControlledUpdate
      ? pastingInfoRef.current.range
      : getChangedRange(update);

    if (changedRange) {
      const { state } = update;

      const range = {
        from: changedRange.from,
        to: changedRange.to,
      };

      editorView.dispatch({
        effects: [pastingEffect.of({ pastingInProgress: true, range })],
        // In order to re-run the decorations and re-generate errors and diagnostics,
        // we have to dispatch a new document.
        changes: {
          from: 0,
          to: editorViewRef.current?.state.doc.length,
          insert: editorViewRef.current?.state.doc,
        },
        selection: state.selection,
      });
    }
  }
}

/**
 * function that returns the changed range of a pasting viewupdate
 * @internal
 */
export function getChangedRange(
  update: ViewUpdate,
): { from: number; to: number } | null {
  // Use any as the changeRanges may not exist on the update type,
  // but it is always there for paste events.
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const changedRanges = (update as any).changedRanges;
  if (changedRanges && changedRanges.length > 0) {
    if (changedRanges.length === 1) {
      return { from: changedRanges[0].fromB, to: changedRanges[0].toB };
    }

    // CodeMirror sometimes provides multiple changed ranges for a single paste event
    // (e.g. when an OR operator is present). In this case we have to rely on the cursor position
    // as it is always at the pasted content.
    if (changedRanges.length > 1) {
      const cursorPos = update.state.selection.main.head;
      for (const range of changedRanges) {
        if (range.toB === cursorPos) {
          return { from: range.fromB, to: range.toB };
        }
      }
    }
  }

  return null;
}

/**
 * We have to handle controlled pasting separately as we don't have a ViewUpdate
 * and can't directly dispatch the updates to the statefield as we would trigger
 * a transaction within a transaction, which would crash CodeMirror.
 * @internal
 */
export function handleControlledPasting(
  transaction: Transaction,
  pastingInfoRef: MutableRefObject<PastingInfo>,
) {
  if (transaction.isUserEvent('input.paste')) {
    const range = { from: 0, to: 0 };

    if (transaction.changes) {
      // Use any as "inserted" may not exist on the update type,
      // but it is always there for paste events.
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const insertions = (transaction.changes as any).inserted;
      range.to = transaction.state.selection.main.anchor;
      // depending on the pasted content and the current FilterField content,
      // there are multiple insertions coming from CodeMirror. If there are multiple,
      // the first one is an empty string and the second one is the actual pasted content.
      // E.g. pasting "foo" into an empty FilterField results in one insertion containing "foo",
      // pasting "foo" into an existing FilterField with content "bar" results in two insertions ("", "foo").
      // Also check if the Array is empty (this happens e.g. when pasting an image while some content is selected).
      if (insertions && Array.isArray(insertions) && insertions.length > 0) {
        if (insertions.length > 1) {
          range.from = Math.max(range.to - insertions[1].length, 0);
        } else {
          range.from = Math.max(range.to - insertions[0].length, 0);
        }
      } else {
        range.from = range.to;
      }
    }
    pastingInfoRef.current = { pastingInProgress: true, range };
  } else if (
    pastingInfoRef.current.pastingInProgress &&
    !transaction.isUserEvent('input.paste')
  ) {
    // Save the info that we want to stop pasting so we can cancel pasting mode after the transaction is through
    pastingInfoRef.current.cancelPastingMode = true;
  }
}
